import React from 'react';
import { ThreeDCard, CardHeader, CardTitle, CardContent, CardFooter } from './ui/3d-card';

const TaskCard = ({ task, currentUser, onPosterClick, onAccept, accepting }) => {
  const acceptedIds = (task.acceptedHustlers || []).map(u => u.id);
  const hasAccepted = currentUser && acceptedIds.includes(currentUser.id);
  const date = task.createdAt ? new Date(task.createdAt) : null;
  const formattedDate = date ? date.toLocaleDateString('en-US', { 
    year: 'numeric', 
    month: 'short', 
    day: 'numeric' 
  }) : '';

  const imageUrl = task.imageUrl || 'https://images.unsplash.com/photo-1464983953574-0892a716854b?auto=format&fit=crop&w=400&q=80';
  const profilePicUrl = (task.poster?.profilePicUrl?.startsWith('/') 
    ? `http://localhost:8080${task.poster.profilePicUrl}` 
    : (task.poster?.profilePicUrl || `https://ui-avatars.com/api/?name=${task.poster?.username || 'U'}`));

  return (
    <ThreeDCard className="w-full h-full flex flex-col">
      <CardHeader className="p-4 pb-2">
        <div className="flex items-center justify-between w-full">
          <span className="text-sm text-gray-400">{formattedDate}</span>
          <span className="px-2 py-1 text-xs font-medium rounded-full" 
                style={{ 
                  backgroundColor: task.status === 'OPEN' ? '#DCFCE7' : '#FEE2E2',
                  color: task.status === 'OPEN' ? '#166534' : '#991B1B'
                }}>
            {task.status}
          </span>
        </div>

        <div className="flex items-center gap-3 mt-2">
          <img
            src={profilePicUrl}
            alt={task.poster?.username || 'User'}
            className="rounded-full w-10 h-10 object-cover border-2 border-white cursor-pointer hover:brightness-90 transition"
            onClick={() => onPosterClick(task.poster?.username)}
          />
          <div>
            <p className="text-sm text-gray-400">Posted by</p>
            <p className="font-medium">{task.poster?.username || 'Unknown'}</p>
          </div>
        </div>

        <CardTitle className="text-xl mt-3 line-clamp-2">{task.title}</CardTitle>
      </CardHeader>

      <CardContent className="flex-1 p-4 pt-0">
        <div className="h-40 overflow-hidden rounded-lg mb-3">
          <img 
            src={imageUrl} 
            alt={task.title} 
            className="w-full h-full object-cover hover:scale-105 transition-transform duration-300"
          />
        </div>
        <p className="text-gray-600 line-clamp-3 text-sm">{task.description}</p>

        {task.tags && (
          <div className="mt-3 flex flex-wrap gap-2">
            {task.tags.split(',').map((tag, index) => (
              <span key={index} className="px-2 py-1 text-xs bg-gray-100 rounded-full text-gray-600">
                {tag.trim()}
              </span>
            ))}
          </div>
        )}
      </CardContent>

      <CardFooter className="p-4 pt-0 flex items-center justify-between">
        <div className="text-lg font-bold text-indigo-600">
          ${task.budget?.toLocaleString() || '0'}
        </div>

        {currentUser?.role === 'HUSTLER' && (
          <button
            onClick={() => onAccept(task.id)}
            disabled={hasAccepted || accepting === task.id}
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
              hasAccepted 
                ? 'bg-green-100 text-green-800 cursor-default' 
                : 'bg-indigo-600 text-white hover:bg-indigo-700'
            }`}
          >
            {hasAccepted ? 'Accepted' : (accepting === task.id ? 'Processing...' : 'Accept Task')}
          </button>
        )}
      </CardFooter>
    </ThreeDCard>
  );
};

export default TaskCard;
